gold_sparql:
SELECT DISTINCT?paper ?paperLabel ?reTask ?reTaskLabel
WHERE {
    ?paper orkgp:P31 ?contribution .

    ?contribution a orkgc:C121001 .

    ?contribution orkgp:P181002 ?reTask .

    OPTIONAL { ?paper rdfs:label ?paperLabel . }
    OPTIONAL { ?reTask rdfs:label ?reTaskLabel . }
}
ORDER BY ?paperLabel

SELECT DISTINCT?paper ?paperLabel ?Nlp_TaskType ?Nlp_TaskTypeLabel
WHERE{
    ?paper orkgp:P31 ?contribution .

    ?contribution a orkgc:C121001 ;
                    orkgp:P181003 ?Nlp_Task .
    ?Nlp_Task orkgp:P181004 ?Nlp_TaskType .

    OPTIONAL { ?paper rdfs:label ?paperLabel . }
    OPTIONAL { ?Nlp_Task rdfs:label ?Nlp_TaskLabel . }
    OPTIONAL { ?Nlp_TaskType rdfs:label ?Nlp_TaskTypeLabel . }
}

SELECT DISTINCT ?Nlp_Task ?Nlp_TaskLabel ?Nlp_TaskInput ?Nlp_InputLabel
WHERE{
    ?paper orkgp:P31 ?contribution .
    ?contribution a orkgc:C121001 ;
                    orkgp:P181003 ?Nlp_Task .

    ?Nlp_Task orkgp:P181005 ?Nlp_TaskInput .

    OPTIONAL { ?Nlp_Task rdfs:label ?Nlp_TaskLabel . }
    OPTIONAL { ?Nlp_TaskInput rdfs:label ?Nlp_InputLabel . }
}

SELECT DISTINCT ?nlpTaskType ?nlpTaskTypeLabel ?outputType ?outputTypeLabel
WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C121001 ;
                orkgp:P181003 ?nlpTask .

  ?nlpTask orkgp:P181004 ?nlpTaskType ;
           orkgp:P181006 ?nlpTaskOutput .

  ?nlpTaskOutput orkgp:P181007 ?outputType .

  OPTIONAL { ?nlpTaskType rdfs:label ?nlpTaskTypeLabel . }
  OPTIONAL { ?outputType rdfs:label ?outputTypeLabel . }
}
ORDER BY ?nlpTaskTypeLabel ?outputTypeLabel

SELECT DISTINCT ?dataset ?datasetLabel
WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C121001 ;
                orkgp:P181011 ?dataset .

  OPTIONAL { ?dataset rdfs:label ?datasetLabel . }
}
ORDER BY ?datasetLabel

SELECT DISTINCT ?naturalLanguage ?naturalLanguageLabel
WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C121001 ;
                orkgp:P181011 ?dataset .

  ?dataset orkgp:P181022 ?dataType .
  ?dataType orkgp:P181025 ?naturalLanguage .

  OPTIONAL { ?naturalLanguage rdfs:label ?naturalLanguageLabel . }
}
ORDER BY ?naturalLanguage

SELECT DISTINCT ?paper ?paperLabel  (xsd:integer(?numberOfAnnotations) AS ?numberOfAnnotations)
WHERE {
    ?paper orkgp:P31 ?contribution .
    ?contribution a orkgc:C121001 ;
                orkgp:P181031 ?annotationProcess .

    ?annotationProcess orkgp:P181032 ?annotator.
    ?annotator  orkgp:P59120 ?numberOfAnnotations .

    OPTIONAL { ?paper rdfs:label ?paperLabel . }

}
ORDER BY DESC(?numberOfAnnotations) ?paperLabel

SELECT DISTINCT ?guidelineAvailability ?guidelineAvailabilityLabel
WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C121001 ;
                orkgp:P181031 ?annotationProcess .

  ?annotationProcess orkgp:P181036 ?annotationScheme .
   ?annotationScheme   orkgp:P181038 ?guidelineAvailability .

  OPTIONAL { ?guidelineAvailability rdfs:label ?guidelineAvailabilityLabel . }
}
ORDER BY ?guidelineAvailability

SELECT ?paper ?paperLabel
       (GROUP_CONCAT(DISTINCT ?metricLabel; separator=", ") AS ?metrics)
WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C121001 ;
                orkgp:HAS_EVALUATION ?evaluation .

  OPTIONAL {?evaluation orkgp:P110006 ?metric .}

  OPTIONAL { ?paper rdfs:label ?paperLabel . }
  OPTIONAL { ?metric rdfs:label ?metricLabel . }
}
GROUP BY ?paper ?paperLabel
ORDER BY ?paperLabel

SELECT ?paper ?paperLabel
       (GROUP_CONCAT(DISTINCT ?baselineTypeLabel; separator=", ") AS ?baselineTypes)
WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C121001 .

  OPTIONAL {
    ?contribution orkgp:HAS_EVALUATION ?evaluation .
    ?evaluation orkgp:P181051 ?baselineComparison .
    ?baselineComparison orkgp:P181052 ?baselineType .
    OPTIONAL { ?baselineType rdfs:label ?baselineTypeLabel . }
  }

  OPTIONAL { ?paper rdfs:label ?paperLabel . }
}
GROUP BY ?paper ?paperLabel
ORDER BY ?paperLabel

SELECT
  ?reTask
  ?reTaskLabel
  ?nlpTaskType
  ?nlpTaskTypeLabel
  ?outputType
  ?outputTypeLabel
  ?paperCount
  (GROUP_CONCAT(DISTINCT ?paperLabel; SEPARATOR=" | ") AS ?papers)
WHERE {

  {
    SELECT
      ?reTask
      ?nlpTaskType
      ?outputType
      (COUNT(DISTINCT ?paper) AS ?paperCount)
    WHERE {
      ?paper orkgp:P31 ?contribution .

      ?contribution a orkgc:C121001 ;
                    orkgp:P181002 ?reTask ;
                    orkgp:P181003 ?nlpTask .

      ?nlpTask orkgp:P181004 ?nlpTaskType ;
               orkgp:P181006 ?nlpTaskOutput .

      ?nlpTaskOutput orkgp:P181007 ?outputType .
    }
    GROUP BY ?reTask ?nlpTaskType ?outputType
  }

  {
    SELECT (MAX(?cnt) AS ?maxCount)
    WHERE {
      {
        SELECT
          ?reTask2
          ?nlpTaskType2
          ?outputType2
          (COUNT(DISTINCT ?paper2) AS ?cnt)
        WHERE {
          ?paper2 orkgp:P31 ?contribution2 .

          ?contribution2 a orkgc:C121001 ;
                         orkgp:P181002 ?reTask2 ;
                         orkgp:P181003 ?nlpTask2 .

          ?nlpTask2 orkgp:P181004 ?nlpTaskType2 ;
                    orkgp:P181006 ?nlpTaskOutput2 .

          ?nlpTaskOutput2 orkgp:P181007 ?outputType2 .
        }
        GROUP BY ?reTask2 ?nlpTaskType2 ?outputType2
      }
    }
  }

  FILTER(?paperCount = ?maxCount)

  ?paper orkgp:P31 ?contribution .

  ?contribution a orkgc:C121001 ;
                orkgp:P181002 ?reTask ;
                orkgp:P181003 ?nlpTask .

  ?nlpTask orkgp:P181004 ?nlpTaskType ;
           orkgp:P181006 ?nlpTaskOutput .

  ?nlpTaskOutput orkgp:P181007 ?outputType .

  OPTIONAL { ?paper rdfs:label ?paperLabel . }
  OPTIONAL { ?reTask rdfs:label ?reTaskLabel . }
  OPTIONAL { ?nlpTaskType rdfs:label ?nlpTaskTypeLabel . }
  OPTIONAL { ?outputType rdfs:label ?outputTypeLabel . }
}
GROUP BY
  ?reTask ?reTaskLabel
  ?nlpTaskType ?nlpTaskTypeLabel
  ?outputType ?outputTypeLabel
  ?paperCount
ORDER BY DESC(?paperCount) ?reTaskLabel ?nlpTaskTypeLabel ?outputTypeLabel

SELECT
  ?reTask
  ?reTaskLabel
  ?nlpTaskInput
  ?nlpTaskInputLabel
  ?outputType
  ?outputTypeLabel
  (COUNT(DISTINCT ?paper) AS ?paperCount)
  (GROUP_CONCAT(DISTINCT ?paperLabel; SEPARATOR=" | ") AS ?papers)
WHERE {
  ?paper orkgp:P31 ?contribution .

  ?contribution a orkgc:C121001 ;
                orkgp:P181002 ?reTask ;
                orkgp:P181003 ?nlpTask .

  ?nlpTask orkgp:P181005 ?nlpTaskInput ;
           orkgp:P181006 ?nlpTaskOutput .

  ?nlpTaskOutput orkgp:P181007 ?outputType .

  OPTIONAL { ?paper rdfs:label ?paperLabel . }
  OPTIONAL { ?reTask rdfs:label ?reTaskLabel . }
  OPTIONAL { ?nlpTaskInput rdfs:label ?nlpTaskInputLabel . }
  OPTIONAL { ?outputType rdfs:label ?outputTypeLabel . }
}
GROUP BY
  ?reTask ?reTaskLabel
  ?nlpTaskInput ?nlpTaskInputLabel
  ?outputType ?outputTypeLabel
ORDER BY ?reTaskLabel DESC(?paperCount) ?nlpTaskInputLabel ?outputTypeLabel

SELECT DISTINCT
  ?paper
  ?paperLabel
  ?licenseType
  ?licenseTypeLabel
  ?locationType
  ?locationTypeLabel
  ?publicAvailabilityLabel
  ?url
WHERE {
  ?paper orkgp:P31 ?contribution .

  ?contribution a orkgc:C121001 ;
                orkgp:P181011 ?dataset .

  ?dataset orkgp:license ?license ;
           orkgp:P181028 ?datasetLocation .

  ?license orkgp:P181026 ?publicAvailability ;
           orkgp:P181027 ?licenseType .

  ?datasetLocation orkgp:P181030 ?locationType;
                    orkgp:P1003 ?url .

  OPTIONAL { ?paper rdfs:label ?paperLabel . }
  OPTIONAL { ?licenseType rdfs:label ?licenseTypeLabel . }
  OPTIONAL { ?locationType rdfs:label ?locationTypeLabel . }
  OPTIONAL { ?publicAvailability rdfs:label ?publicAvailabilityLabel . }

}
ORDER BY ?publicAvailabilityLabel ?paperLabel

SELECT
  ?sourceType
  ?sourceTypeLabel
  ?sourceDomain
  ?sourceDomainLabel
  ?paperCount
  (GROUP_CONCAT(DISTINCT ?paperLabel; SEPARATOR=" | ") AS ?papers)
WHERE {

  {
    SELECT
      ?sourceType
      ?sourceDomain
      (COUNT(DISTINCT ?paper) AS ?paperCount)
    WHERE {
      ?paper orkgp:P31 ?contribution .

      ?contribution a orkgc:C121001 ;
                    orkgp:P181011 ?dataset .

      ?dataset orkgp:P181017 ?dataSource .

      ?dataSource orkgp:P181018 ?sourceType ;
                  orkgp:P181020 ?sourceDomain .
    }
    GROUP BY ?sourceType ?sourceDomain
  }

  {
    SELECT (MAX(?cnt) AS ?maxCount)
    WHERE {
      {
        SELECT
          ?sourceType2
          ?sourceDomain2
          (COUNT(DISTINCT ?paper2) AS ?cnt)
        WHERE {
          ?paper2 orkgp:P31 ?contribution2 .

          ?contribution2 a orkgc:C121001 ;
                         orkgp:P181011 ?dataset2 .

          ?dataset2 orkgp:P181017 ?dataSource2 .

          ?dataSource2 orkgp:P181018 ?sourceType2 ;
                       orkgp:P181020 ?sourceDomain2 .
        }
        GROUP BY ?sourceType2 ?sourceDomain2
      }
    }
  }

  FILTER(?paperCount = ?maxCount)

  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C121001 ;
                orkgp:P181011 ?dataset .
  ?dataset orkgp:P181017 ?dataSource .
  ?dataSource orkgp:P181018 ?sourceType ;
              orkgp:P181020 ?sourceDomain .

  OPTIONAL { ?paper rdfs:label ?paperLabel . }
  OPTIONAL { ?sourceType rdfs:label ?sourceTypeLabel . }
  OPTIONAL { ?sourceDomain rdfs:label ?sourceDomainLabel . }
}
GROUP BY
  ?sourceType ?sourceTypeLabel
  ?sourceDomain ?sourceDomainLabel
  ?paperCount
ORDER BY DESC(?paperCount) ?sourceTypeLabel ?sourceDomainLabel

SELECT
  ?paper
  ?paperLabel
  (GROUP_CONCAT(DISTINCT ?guidelineAvailabilityLabel; SEPARATOR=" | ") AS ?guidelineAvailabilities)
  (GROUP_CONCAT(DISTINCT ?measuredAgreement; SEPARATOR=" | ") AS ?measuredAgreements)
  (GROUP_CONCAT(DISTINCT ?metricLabel; SEPARATOR=" | ") AS ?metrics)
  (GROUP_CONCAT(DISTINCT ?conflictResolutionLabel; SEPARATOR=" | ") AS ?conflictResolutions)
WHERE {
  ?paper orkgp:P31 ?contribution .

  ?contribution a orkgc:C121001 ;
                orkgp:P181031 ?annotationProcess .

  ?annotationProcess orkgp:P181036 ?annotationScheme ;
                     orkgp:P181041 ?annotatorAgreement .

  ?annotationScheme orkgp:P181038 ?guidelineAvailability .
  ?annotatorAgreement orkgp:P181045 ?measuredAgreement ;
                      orkgp:P181042 ?metric ;
                      orkgp:P181044 ?conflictResolution .

  OPTIONAL { ?paper rdfs:label ?paperLabel . }
  OPTIONAL { ?guidelineAvailability rdfs:label ?guidelineAvailabilityLabel . }
  OPTIONAL { ?metric rdfs:label ?metricLabel . }
  OPTIONAL { ?conflictResolution rdfs:label ?conflictResolutionLabel . }
}
GROUP BY ?paper ?paperLabel
ORDER BY ?paperLabel

SELECT
    ?paper
    ?paperLabel
    ?baselineDetail
    (COUNT(DISTINCT ?baselineType) AS ?baselineTypeCount)
    (GROUP_CONCAT(DISTINCT ?baselineTypeLabel; SEPARATOR=" | ") AS ?baselineTypes)
WHERE {
    ?paper orkgp:P31 ?contribution .

    ?contribution a orkgc:C121001 ;
                orkgp:HAS_EVALUATION ?evaluation .

    ?evaluation orkgp:P181051 ?baselineComparison .

    ?baselineComparison orkgp:P181052 ?baselineType ;
                orkgp:P181053 ?baselineDetail .


    OPTIONAL { ?paper rdfs:label ?paperLabel . }
    OPTIONAL { ?baselineType rdfs:label ?baselineTypeLabel . }

}

GROUP BY ?paper ?paperLabel ?baselineDetail
HAVING(COUNT(DISTINCT ?baselineType) > 1)
ORDER BY ?paperLabel

SELECT
  ?approachType
  ?approachTypeLabel
  ?algorithm
  ?algorithmLabel
  ?paperCount
  (GROUP_CONCAT(DISTINCT ?paperLabel; SEPARATOR=" | ") AS ?papers)
WHERE {

  {
    SELECT
      ?approachType
      ?algorithm
      (COUNT(DISTINCT ?paper) AS ?paperCount)
    WHERE {
      ?paper orkgp:P31 ?contribution .

      ?contribution a orkgc:C121001 ;
                    orkgp:P181046 ?implementedApproach .

      ?implementedApproach orkgp:P5043 ?approachType ;
                           orkgp:P58069 ?algorithm .
    }
    GROUP BY ?approachType ?algorithm
  }

  {
    SELECT (MAX(?cnt) AS ?maxCount)
    WHERE {
      {
        SELECT
          ?approachType2
          ?algorithm2
          (COUNT(DISTINCT ?paper2) AS ?cnt)
        WHERE {
          ?paper2 orkgp:P31 ?contribution2 .

          ?contribution2 a orkgc:C121001 ;
                         orkgp:P181046 ?implementedApproach2 .

          ?implementedApproach2 orkgp:P5043 ?approachType2 ;
                                orkgp:P58069 ?algorithm2 .
        }
        GROUP BY ?approachType2 ?algorithm2
      }
    }
  }

  FILTER(?paperCount = ?maxCount)

  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C121001 ;
                orkgp:P181046 ?implementedApproach .
  ?implementedApproach orkgp:P5043 ?approachType ;
                       orkgp:P58069 ?algorithm .

  OPTIONAL { ?paper rdfs:label ?paperLabel . }
  OPTIONAL { ?approachType rdfs:label ?approachTypeLabel . }
  OPTIONAL { ?algorithm rdfs:label ?algorithmLabel . }
}
GROUP BY
  ?approachType ?approachTypeLabel
  ?algorithm ?algorithmLabel
  ?paperCount
ORDER BY DESC(?paperCount) ?approachTypeLabel ?algorithmLabel

SELECT
  ?paper
  ?paperLabel
  ?releaseFormats
  ?publicationTypes
  ?urls
  ?documentationTypes
WHERE {
  {
    SELECT DISTINCT ?paper ?paperLabel
    WHERE {
      ?paper orkgp:P31 ?contribution .
      ?contribution a orkgc:C121001 ;
                    orkgp:P181046 ?implementedApproach .
      ?implementedApproach orkgp:release ?release .
      OPTIONAL { ?paper rdfs:label ?paperLabel . }
    }
  }

  OPTIONAL {
    SELECT
      ?paper
      (GROUP_CONCAT(DISTINCT ?releaseFormatLabel; SEPARATOR=" | ") AS ?releaseFormats)
    WHERE {
      ?paper orkgp:P31 ?contribution .
      ?contribution a orkgc:C121001 ;
                    orkgp:P181046 ?implementedApproach .
      ?implementedApproach orkgp:release ?release .
      ?release orkgp:P181049 ?releaseFormat .
      OPTIONAL { ?releaseFormat rdfs:label ?releaseFormatLabel . }
    }
    GROUP BY ?paper
  }

  OPTIONAL {
    SELECT
      ?paper
      (GROUP_CONCAT(DISTINCT ?locationTypeLabel; SEPARATOR=" | ") AS ?publicationTypes)
    WHERE {
      ?paper orkgp:P31 ?contribution .
      ?contribution a orkgc:C121001 ;
                    orkgp:P181046 ?implementedApproach .
      ?implementedApproach orkgp:release ?release .
      ?release orkgp:P181029 ?locationType .
      OPTIONAL { ?locationType rdfs:label ?locationTypeLabel . }
    }
    GROUP BY ?paper
  }

  OPTIONAL {
    SELECT
      ?paper
      (GROUP_CONCAT(DISTINCT STR(?url); SEPARATOR=" | ") AS ?urls)
    WHERE {
      ?paper orkgp:P31 ?contribution .
      ?contribution a orkgc:C121001 ;
                    orkgp:P181046 ?implementedApproach .
      ?implementedApproach orkgp:release ?release .
      ?release orkgp:P1003 ?url .
    }
    GROUP BY ?paper
  }

  OPTIONAL {
    SELECT
      ?paper
      (GROUP_CONCAT(DISTINCT ?documentationTypeLabel; SEPARATOR=" | ") AS ?documentationTypes)
    WHERE {
      ?paper orkgp:P31 ?contribution .
      ?contribution a orkgc:C121001 ;
                    orkgp:P181046 ?implementedApproach .
      ?implementedApproach orkgp:P41835 ?documentationType .
      OPTIONAL { ?documentationType rdfs:label ?documentationTypeLabel . }
    }
    GROUP BY ?paper
  }
}
ORDER BY ?paperLabel

SELECT DISTINCT
  ?paper
  ?paperLabel
  ?productionTime
WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C121001 ;
                orkgp:P181011 ?dataset .

  ?dataset orkgp:P181016 ?productionTime .
  FILTER(STR(?productionTime) != "Not reported")

  OPTIONAL { ?paper rdfs:label ?paperLabel . }
}
ORDER BY ?paperLabel ?productionTime

SELECT ?publicationDecade ?validationProcedureLabel ?paperCount
        (GROUP_CONCAT(DISTINCT ?paperLabel; SEPARATOR=" | ") AS ?papers)
WHERE {
  {
    SELECT ?publicationDecade ?validationProcedureLabel ?paperCount
    WHERE {
      {
        SELECT ?publicationDecade ?validationProcedureLabel (COUNT(DISTINCT ?paper) AS ?paperCount)
        WHERE {
            ?paper orkgp:P31 ?contribution .
            ?paper orkgp:P29 ?year .
            ?contribution a orkgc:C121001 .

            ?contribution orkgp:HAS_EVALUATION ?evaluation .
            ?evaluation orkgp:P181050 ?validationProcedure .
            ?validationProcedure rdfs:label ?validationProcedureLabel .

            FILTER(xsd:integer(?year) >= 2006 && xsd:integer(?year) <= 2025)
            FILTER(LCASE(STR(?validationProcedureLabel)) != "not reported")

            BIND(xsd:integer(FLOOR(xsd:decimal(?year) / 10) * 10) AS ?decadeStart)
            BIND(CONCAT(STR(?decadeStart), "s") AS ?publicationDecade)
        }
          GROUP BY ?publicationDecade ?validationProcedureLabel
      }

      {
        SELECT ?publicationDecade (MAX(?cnt) AS ?maxCount)
        WHERE {
          {
            SELECT ?publicationDecade ?validationProcedureLabel (COUNT(DISTINCT ?paper) AS ?cnt)
            WHERE {
                ?paper orkgp:P31 ?contribution .
                ?paper orkgp:P29 ?year .
                ?contribution a orkgc:C121001 .

                ?contribution orkgp:HAS_EVALUATION ?evaluation .
                ?evaluation orkgp:P181050 ?validationProcedure .
                ?validationProcedure rdfs:label ?validationProcedureLabel .

                FILTER(xsd:integer(?year) >= 2006 && xsd:integer(?year) <= 2025)
                FILTER(LCASE(STR(?validationProcedureLabel)) != "not reported")

                BIND(xsd:integer(FLOOR(xsd:decimal(?year) / 10) * 10) AS ?decadeStart)
                BIND(CONCAT(STR(?decadeStart), "s") AS ?publicationDecade)
              }
              GROUP BY ?publicationDecade ?validationProcedureLabel
          }
        }
        GROUP BY ?publicationDecade
      }

      FILTER(?paperCount = ?maxCount)
    }
  }

    ?paper orkgp:P31 ?contribution .
    ?paper orkgp:P29 ?year .
    ?contribution a orkgc:C121001 .

    ?contribution orkgp:HAS_EVALUATION ?evaluation .
    ?evaluation orkgp:P181050 ?validationProcedure .
    ?validationProcedure rdfs:label ?validationProcedureLabel .

    FILTER(xsd:integer(?year) >= 2006 && xsd:integer(?year) <= 2025)
    FILTER(LCASE(STR(?validationProcedureLabel)) != "not reported")

    BIND(xsd:integer(FLOOR(xsd:decimal(?year) / 10) * 10) AS ?decadeStart2)
    BIND(CONCAT(STR(?decadeStart2), "s") AS ?publicationDecade)

    OPTIONAL { ?paper rdfs:label ?paperLabel . }
}
GROUP BY ?publicationDecade ?validationProcedureLabel ?paperCount
ORDER BY ?publicationDecade ?validationProcedureLabel

SELECT ?publicationDecade ?datasourceDomainLabel ?paperCount
       (GROUP_CONCAT(DISTINCT ?paperLabel; SEPARATOR=" | ") AS ?papers)
WHERE {
  {
    SELECT ?publicationDecade ?datasourceDomainLabel ?paperCount
    WHERE {
        {
            SELECT ?publicationDecade ?datasourceDomainLabel (COUNT(DISTINCT ?paper) AS ?paperCount)
            WHERE {
            ?paper orkgp:P31 ?contribution .
            ?paper orkgp:P29 ?year .
            ?contribution a orkgc:C121001 .

            ?contribution orkgp:P181011 ?NLPdataset .
            ?NLPdataset orkgp:P181017 ?NLPdatasource .
            ?NLPdatasource orkgp:P181020 ?datasourceDomain .
            ?datasourceDomain rdfs:label ?datasourceDomainLabel .

            FILTER(xsd:integer(?year) >= 2010 && xsd:integer(?year) <= 2029)
            FILTER(LCASE(STR(?datasourceDomainLabel)) != "not reported")

            BIND(IF(xsd:integer(?year) <= 2019, "2010s", "2020s") AS ?publicationDecade)
            }
            GROUP BY ?publicationDecade ?datasourceDomainLabel
        }

        {
            SELECT ?publicationDecade (MAX(?cnt) AS ?maxCount)
            WHERE {
            {
                SELECT ?publicationDecade ?datasourceDomainLabel (COUNT(DISTINCT ?paper) AS ?cnt)
                WHERE {
                ?paper orkgp:P31 ?contribution .
                ?paper orkgp:P29 ?year .
                ?contribution a orkgc:C121001 .

                ?contribution orkgp:P181011 ?NLPdataset .
                ?NLPdataset orkgp:P181017 ?NLPdatasource .
                ?NLPdatasource orkgp:P181020 ?datasourceDomain .
                ?datasourceDomain rdfs:label ?datasourceDomainLabel .

                FILTER(xsd:integer(?year) >= 2010 && xsd:integer(?year) <= 2029)
                FILTER(LCASE(STR(?datasourceDomainLabel)) != "not reported")

                BIND(IF(xsd:integer(?year) <= 2019, "2010s", "2020s") AS ?publicationDecade)
                }
                GROUP BY ?publicationDecade ?datasourceDomainLabel
            }
            }
            GROUP BY ?publicationDecade
        }

        FILTER(?paperCount = ?maxCount)
    }
  }

    ?paper orkgp:P31 ?contribution .
    ?paper orkgp:P29 ?year .
    ?contribution a orkgc:C121001 .

    ?contribution orkgp:P181011 ?NLPdataset .
    ?NLPdataset orkgp:P181017 ?NLPdatasource .
    ?NLPdatasource orkgp:P181020 ?datasourceDomain .
    ?datasourceDomain rdfs:label ?datasourceDomainLabel .

    FILTER(xsd:integer(?year) >= 2010 && xsd:integer(?year) <= 2029)
    FILTER(LCASE(STR(?datasourceDomainLabel)) != "not reported")

    BIND(IF(xsd:integer(?year) <= 2019, "2010s", "2020s") AS ?publicationDecade)

    OPTIONAL { ?paper rdfs:label ?paperLabel . }
}
GROUP BY ?publicationDecade ?datasourceDomainLabel ?paperCount
ORDER BY ?publicationDecade ?datasourceDomainLabel

ASK {
    ?paper orkgp:P31 ?contribution .
    ?contribution a orkgc:C121001 .

    ?contribution orkgp:P181031 ?annotationProcess .
    ?annotationProcess orkgp:P181041 ?annotatorAgreement .
    ?annotatorAgreement rdfs:label ?annotatorAgreementLabel .

    FILTER(LCASE(STR(?annotatorAgreementLabel)) != "not reported")

    FILTER NOT EXISTS {
        ?annotatorAgreement orkgp:P181042 ?metric .
        ?metric rdfs:label ?metricLabel .
        FILTER(LCASE(STR(?metricLabel)) != "not reported")
    }

    FILTER NOT EXISTS {
        ?annotatorAgreement orkgp:P181044 ?conflictResolution .
        ?conflictResolution rdfs:label ?conflictResolutionLabel .
        FILTER(LCASE(STR(?conflictResolutionLabel)) != "not reported")
    }
}

SELECT DISTINCT ?paper ?paperLabel
WHERE {
    ?paper orkgp:P31 ?contribution .
    ?contribution a orkgc:C121001 .
    ?contribution orkgp:P181046 ?implementedApproach .
    ?implementedApproach orkgp:release ?release .

    {
        ?release orkgp:P181049 ?releaseFormat .
        ?releaseFormat rdfs:label ?releaseFormatLabel .
        FILTER(LCASE(STR(?releaseFormatLabel)) != "not reported")
    }
    UNION
    {
        ?release orkgp:P181029 ?releaseLocationType .
        ?releaseLocationType rdfs:label ?releaseLocationTypeLabel .
        FILTER(LCASE(STR(?releaseLocationTypeLabel)) != "not reported")
    }

    FILTER NOT EXISTS {
        ?implementedApproach orkgp:P181027 ?licenseType .
        ?licenseType rdfs:label ?licenseTypeLabel .
        FILTER(LCASE(STR(?licenseTypeLabel)) != "not reported")
    }

    OPTIONAL { ?paper rdfs:label ?paperLabel . }
}
ORDER BY ?paperLabel

ASK {
    ?paper orkgp:P31 ?contribution .
    ?contribution a orkgc:C121001 .

    ?contribution orkgp:HAS_EVALUATION ?evaluation .
    ?evaluation orkgp:P181051 ?baselineComparison .
    ?baselineComparison rdfs:label ?baselineComparisonLabel .

    FILTER(LCASE(STR(?baselineComparisonLabel)) != "not reported")

    FILTER(
        NOT EXISTS {
        ?baselineComparison orkgp:P181052 ?baselineType .
        ?baselineType rdfs:label ?baselineTypeLabel .
        FILTER(LCASE(STR(?baselineTypeLabel)) != "not reported")
        }
        ||
        NOT EXISTS {
        ?baselineComparison orkgp:P181053 ?baselineDetail .
        FILTER(LCASE(STR(?baselineDetail)) != "not reported")
        }
    )
}

